diff --git a/llvm/lib/Analysis/InstructionSimplify.cpp b/llvm/lib/Analysis/InstructionSimplify.cpp
index 3f3f6c6e0d1a..95ce0744a7d4 100644
--- a/llvm/lib/Analysis/InstructionSimplify.cpp
+++ b/llvm/lib/Analysis/InstructionSimplify.cpp
@@ -4607,6 +4607,28 @@ static Value *simplifySelectInst(Value *Cond, Value *TrueVal, Value *FalseVal,
           match(Cond, m_c_LogicalOr(m_Specific(X), m_Specific(Y))))
         return X;
     }
+
+    // Absorption: (a && b) || b = b, (b && a) || b = b
+    // select (select a, b, false), true, b -> b
+    // select (select a, b, false), true, a -> a
+    Value *A, *B;
+    if (match(TrueVal, m_One()) &&
+        match(Cond, m_Select(m_Value(A), m_Value(B), m_Zero()))) {
+      if (match(FalseVal, m_Specific(B)))
+        return B;
+      if (match(FalseVal, m_Specific(A)))
+        return A;
+    }
+    // Absorption: (a || b) && b = b, (b || a) && b = b
+    // select (select a, b, true), false, b -> b
+    // select (select a, b, true), false, a -> a
+    if (match(FalseVal, m_ZeroInt()) &&
+        match(Cond, m_Select(m_Value(A), m_Value(B), m_One()))) {
+      if (match(TrueVal, m_Specific(B)))
+        return B;
+      if (match(TrueVal, m_Specific(A)))
+        return A;
+    }
   }

   // select ?, X, X -> X
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index e7d8208f94fd..64c2e60b9d2d 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2965,7 +2965,14 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
   if (match(CondVal, m_Select(m_Value(A), m_Value(B), m_Zero())) &&
       match(TrueVal, m_Specific(B)) && match(FalseVal, m_Zero()))
     return replaceOperand(SI, 0, A);
-
+  // select (select a, b, false), true, b -> b  (absorption: (a && b) || b = b)
+  if (match(CondVal, m_Select(m_Value(A), m_Value(B), m_Zero())) &&
+      match(TrueVal, m_One()) && match(FalseVal, m_Specific(B)))
+    return replaceInstUsesWith(SI, B);
+  // select (select a, b, true), false, b -> b  (absorption: (a || b) && b = b)
+  if (match(CondVal, m_Select(m_Value(A), m_Value(B), m_One())) &&
+      match(TrueVal, m_Specific(B)) && match(FalseVal, m_Zero()))
+    return replaceInstUsesWith(SI, B);
   // ~(A & B) & (A | B) --> A ^ B
   if (match(&SI, m_c_LogicalAnd(m_Not(m_LogicalAnd(m_Value(A), m_Value(B))),
                                 m_c_LogicalOr(m_Deferred(A), m_Deferred(B)))))

